            document.body,
          )}
          <DndContext
            sensors={trackSensors}
            collisionDetection={closestCenter}
            onDragEnd={onTrackDragEnd}
          >
            <SortableContext
              items={tracks.map((track) => `track-${track.id}`)}
              strategy={verticalListSortingStrategy}
            >
              {tracks.map((track, index) => {
                const row = rows[index];
                if (!row) {
                  return null;
                }

                return (
                  <SortableRow
                    key={track.id}
                    row={row}
                    track={track}
                    rowHeight={rowHeight}
                    startLeft={startLeft}
                    pixelsPerSecond={pixelsPerSecond}
                    selectedTrackId={selectedTrackId}
                    resizeOverrides={rowResizeOverrides[index] ?? EMPTY_RESIZE_OVERRIDES}
                    getActionRender={getActionRender}
                    onSelectTrack={onSelectTrack}
                    onTrackChange={onTrackChange}
                    onRemoveTrack={onRemoveTrack}
                    onResizePointerDown={handleResizePointerDown}
                    onResizePointerMove={handleResizePointerMove}
                    onResizeEnd={endResize}
                  />
                );
              })}

import { createContext, useContext, useMemo } from 'react';
import type {
  TimelineEditorContextValue,
  TimelineEditorDataContextValue,
  TimelineEditorOpsContextValue,
} from '@/tools/video-editor/hooks/useTimelineState.types';

const TimelineEditorDataContext = createContext<TimelineEditorDataContextValue | null>(null);
const TimelineEditorOpsContext = createContext<TimelineEditorOpsContextValue | null>(null);

export function TimelineEditorDataContextProvider({
  value,
  children,
}: {
  value: TimelineEditorDataContextValue;
  children: React.ReactNode;
}) {
  return (
    <TimelineEditorDataContext.Provider value={value}>
      {children}
    </TimelineEditorDataContext.Provider>
  );
}

export function TimelineEditorOpsContextProvider({
  value,
  children,
}: {
  value: TimelineEditorOpsContextValue;
  children: React.ReactNode;
}) {
  return (
    <TimelineEditorOpsContext.Provider value={value}>
      {children}
    </TimelineEditorOpsContext.Provider>
  );
}

export function useTimelineEditorData(): TimelineEditorDataContextValue {
  const context = useContext(TimelineEditorDataContext);
  if (!context) {
    throw new Error('useTimelineEditorData must be used within TimelineEditorDataContextProvider');
  }

  return context;
}

export function useTimelineEditorOps(): TimelineEditorOpsContextValue {
  const context = useContext(TimelineEditorOpsContext);
  if (!context) {
    throw new Error('useTimelineEditorOps must be used within TimelineEditorOpsContextProvider');
  }

  return context;
}

/**
 * @deprecated Prefer `useTimelineEditorData()` and `useTimelineEditorOps()`.
 */
export function useTimelineEditorContext(): TimelineEditorContextValue {
  const data = useTimelineEditorData();
  const ops = useTimelineEditorOps();

  return useMemo(
    () => ({ ...data, ...ops }),
    [data, ops],
  );
}

// @vitest-environment jsdom
import { fireEvent, render } from '@testing-library/react';
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import { TimelineCanvas } from '@/tools/video-editor/components/TimelineEditor/TimelineCanvas';
import type { TrackDefinition } from '@/tools/video-editor/types';
import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

const useTimelineEditorDataMock = vi.fn();

vi.mock('@/tools/video-editor/contexts/TimelineEditorContext', async () => {
  const actual = await vi.importActual<typeof import('@/tools/video-editor/contexts/TimelineEditorContext')>(
    '@/tools/video-editor/contexts/TimelineEditorContext',
  );

  return {
    ...actual,
    useTimelineEditorData: () => useTimelineEditorDataMock(),
  };
});

let pointerCaptures = new WeakMap<HTMLElement, Set<number>>();

function getPointerCaptures(element: HTMLElement) {
  let captures = pointerCaptures.get(element);
  if (!captures) {
    captures = new Set<number>();
    pointerCaptures.set(element, captures);
  }

  return captures;
}

const track: TrackDefinition = { id: 'V1', kind: 'visual', label: 'V1' };
const action: TimelineAction = { id: 'clip-1', start: 0, end: 2, effectId: 'effect-clip-1' };
const row: TimelineRow = { id: 'V1', actions: [action] };

function renderCanvas(params?: {
  pendingOpsRef?: React.MutableRefObject<number>;
  onActionResizeStart?: ReturnType<typeof vi.fn>;
  onActionResizeEnd?: ReturnType<typeof vi.fn>;
  getActionRender?: ReturnType<typeof vi.fn>;
}) {
  const pendingOpsRef = params?.pendingOpsRef ?? { current: 0 };
  useTimelineEditorDataMock.mockReturnValue({ pendingOpsRef });

  const onActionResizeStart = params?.onActionResizeStart ?? vi.fn();
  const onActionResizeEnd = params?.onActionResizeEnd ?? vi.fn();
  const getActionRender = params?.getActionRender ?? vi.fn(() => <div>clip</div>);

  const renderResult = render(
    <TimelineCanvas
      rows={[row]}
      tracks={[track]}
      scale={1}
      scaleWidth={100}
      scaleSplitCount={1}
      startLeft={0}
      rowHeight={48}
      minScaleCount={1}
      maxScaleCount={10}
      selectedTrackId={null}
      getActionRender={getActionRender}
      onSelectTrack={vi.fn()}
      onTrackChange={vi.fn()}
      onRemoveTrack={vi.fn()}
      onTrackDragEnd={vi.fn()}
      trackSensors={[] as never}
      onCursorDrag={vi.fn()}
      onClickTimeArea={vi.fn()}
      onActionResizeStart={onActionResizeStart}
      onActionResizeEnd={onActionResizeEnd}
    />,
  );

  const leftHandle = renderResult.container.querySelector('[data-action-id="clip-1"] .cursor-ew-resize');
  if (!(leftHandle instanceof HTMLElement)) {
    throw new Error('expected resize handle');
  }

  return {
    ...renderResult,
    leftHandle,
    pendingOpsRef,
    onActionResizeStart,
    onActionResizeEnd,
    getActionRender,
  };
}

beforeEach(() => {
  Object.defineProperties(HTMLElement.prototype, {
    setPointerCapture: {
      configurable: true,
      value(pointerId: number) {
        getPointerCaptures(this).add(pointerId);
      },
    },
    releasePointerCapture: {
      configurable: true,
      value(pointerId: number) {
        getPointerCaptures(this).delete(pointerId);
      },
    },
    hasPointerCapture: {
      configurable: true,
      value(pointerId: number) {
        return getPointerCaptures(this).has(pointerId);
      },
    },
  });
});

afterEach(() => {
  useTimelineEditorDataMock.mockReset();
  pointerCaptures = new WeakMap<HTMLElement, Set<number>>();
});

describe('TimelineCanvas resize pending ops', () => {
  it('increments on resize start and decrements on resize end', () => {
    const { leftHandle, pendingOpsRef, onActionResizeStart, onActionResizeEnd } = renderCanvas();

    fireEvent.pointerDown(leftHandle, {
      button: 0,
      pointerId: 7,
      clientX: 120,
    });

    expect(pendingOpsRef.current).toBe(1);
    expect(onActionResizeStart).toHaveBeenCalledTimes(1);

    fireEvent.pointerUp(leftHandle, {
      pointerId: 7,
      clientX: 120,
    });

    expect(pendingOpsRef.current).toBe(0);
    expect(onActionResizeEnd).toHaveBeenCalledTimes(1);
  });

  it('decrements on pointercancel without firing resize end', () => {
    const { leftHandle, pendingOpsRef, onActionResizeEnd } = renderCanvas();

    fireEvent.pointerDown(leftHandle, {
      button: 0,
      pointerId: 8,
      clientX: 120,
    });

    expect(pendingOpsRef.current).toBe(1);

    fireEvent.pointerCancel(leftHandle, {
      pointerId: 8,
      clientX: 120,
    });

    expect(pendingOpsRef.current).toBe(0);
    expect(onActionResizeEnd).not.toHaveBeenCalled();
  });

  it('passes the rendered clip width into getActionRender', () => {
    const getActionRender = vi.fn(() => <div>clip</div>);
    renderCanvas({ getActionRender });

    expect(getActionRender).toHaveBeenCalledWith(action, row, 200);
  });
});

